  --secondary-foreground: hsl(210, 40%, 98%);
  --muted: hsl(217.2, 32.6%, 17.5%);
  --muted-foreground: hsl(215, 20.2%, 65.1%);
  --accent: hsl(217.2, 32.6%, 17.5%);
  --accent-foreground: hsl(210, 40%, 98%);
  --destructive: hsl(0, 62.8%, 30.6%);
  --destructive-foreground: hsl(210, 40%, 98%);
  --border: hsl(217.2, 32.6%, 17.5%);
  --input: hsl(217.2, 32.6%, 17.5%);
  --ring: hsl(224.3, 76.3%, 94.1%);
  --chart-1: hsl(221.2, 83.2%, 53.3%);
  --chart-2: hsl(159.8, 100%, 36.1%);
  --chart-3: hsl(42.0, 92.8%, 56.3%);
  --chart-4: hsl(147.1, 78.5%, 41.96%);
  --chart-5: hsl(341.5, 75.2%, 50.98%);
  --sidebar: hsl(222.2, 84%, 4.9%);
  --sidebar-foreground: hsl(210, 40%, 98%);
  --sidebar-primary: hsl(221.2, 83.2%, 53.3%);
  --sidebar-primary-foreground: hsl(210, 40%, 98%);
  --sidebar-accent: hsl(217.2, 32.6%, 17.5%);
  --sidebar-accent-foreground: hsl(210, 40%, 98%);
  --sidebar-border: hsl(217.2, 32.6%, 17.5%);
  --sidebar-ring: hsl(221.2, 83.2%, 53.3%);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply bg-background text-foreground font-sans antialiased;
  }
}

/* Custom gradient and effects matching the design reference */
.hero-gradient {
  background: linear-gradient(135deg, hsl(var(--primary) / 0.1) 0%, hsl(217.2, 91.2%, 70% / 0.1) 100%);
}

.button-gradient {
  background: linear-gradient(135deg, hsl(var(--primary)) 0%, hsl(217.2, 91.2%, 60%) 100%) !important;
  color: white !important;
  border: none !important;
  box-shadow: 0 4px 14px hsl(var(--primary) / 0.3);
  transition: all 0.3s ease;
}

.button-gradient:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 25px hsl(var(--primary) / 0.4) !important;
  background: linear-gradient(135deg, hsl(var(--primary) / 0.9) 0%, hsl(217.2, 91.2%, 55%) 100%) !important;
  color: white !important;
}

.card-hover {
  transition: all 0.3s ease;
}

.card-hover:hover {
  transform: translateY(-2px);
  box-shadow: 0 20px 40px hsl(var(--primary) / 0.1);
}

.feature-icon {
  background: linear-gradient(135deg, hsl(var(--primary) / 0.1) 0%, hsl(217.2, 91.2%, 70% / 0.1) 100%);
}

.modal-backdrop {
  backdrop-filter: blur(8px);
}

/* Ensure rounded corners are consistent */
.rounded-xl {
  border-radius: 0.75rem;
}

/* Upgrade button shake animation */
@keyframes shake {
  0%, 100% { transform: translateX(0); }
  25% { transform: translateX(-2px); }
  75% { transform: translateX(2px); }
}

@keyframes pulse-glow {
  0%, 100% { box-shadow: 0 4px 14px hsl(var(--primary) / 0.3); }
  50% { box-shadow: 0 6px 20px hsl(var(--primary) / 0.5); }
}

.shake-animation {
  animation: shake 0.5s ease-in-out infinite;
}

.pulse-glow-animation {
  animation: pulse-glow 2s ease-in-out infinite;
}

/* Premium styling enhancements */
.premium-gradient {
  background: linear-gradient(135deg, hsl(var(--primary) / 0.08) 0%, hsl(217.2, 91.2%, 90% / 0.08) 50%, hsl(var(--primary) / 0.12) 100%);
  backdrop-filter: blur(1px);
}

.premium-card {
  background: linear-gradient(145deg, hsl(var(--card)), hsl(var(--card) / 0.98));
  border: 1px solid hsl(var(--border));
  box-shadow: 0 4px 20px hsl(var(--foreground) / 0.03), 0 1px 3px hsl(var(--foreground) / 0.08);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.premium-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 40px hsl(var(--foreground) / 0.08), 0 4px 16px hsl(var(--primary) / 0.12);
}

.stat-card {
  background: linear-gradient(145deg, hsl(var(--card)), hsl(var(--card) / 0.95));
  border: 1px solid hsl(var(--border) / 0.5);
  box-shadow: 0 2px 12px hsl(var(--foreground) / 0.04);
  transition: all 0.2s ease;
}

.stat-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px hsl(var(--foreground) / 0.08);
}

.premium-button {
  background: linear-gradient(135deg, hsl(var(--primary)) 0%, hsl(217.2, 91.2%, 60%) 100%);
  box-shadow: 0 4px 16px hsl(var(--primary) / 0.4);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: none;
  color: white;
}

.premium-button:hover {
  transform: translateY(-3px);
  box-shadow: 0 12px 32px hsl(var(--primary) / 0.5);
  background: linear-gradient(135deg, hsl(var(--primary) / 0.9) 0%, hsl(217.2, 91.2%, 55%) 100%);
  color: white;
}

.glass-effect {
  background: linear-gradient(145deg, hsl(var(--background) / 0.8), hsl(var(--background) / 0.6));
  backdrop-filter: blur(12px);
  border: 1px solid hsl(var(--border) / 0.3);
}

.text-gradient {
  background: linear-gradient(135deg, hsl(var(--primary)) 0%, hsl(217.2, 91.2%, 65%) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.dashboard-header {
  background: linear-gradient(145deg, hsl(var(--card)), hsl(var(--card) / 0.98));
  border-bottom: 1px solid hsl(var(--border) / 0.8);
  box-shadow: 0 1px 3px hsl(var(--foreground) / 0.05);
}

.quick-action-button {
  background: linear-gradient(145deg, hsl(var(--background)), hsl(var(--muted) / 0.3));
  border: 1px solid hsl(var(--border) / 0.5);
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

.quick-action-button:hover {
  background: linear-gradient(145deg, hsl(var(--muted) / 0.5), hsl(var(--muted) / 0.7));
  border-color: hsl(var(--primary) / 0.3);
  transform: translateY(-1px);
  box-shadow: 0 4px 12px hsl(var(--foreground) / 0.06);
}

.rounded-2xl {
  border-radius: 1rem;
}

/* Focus styles for accessibility */
.focus\:ring-2:focus {
  --tw-ring-offset-shadow: var(--tw-ring-inset) 0 0 0 var(--tw-ring-offset-width) var(--tw-ring-offset-color);
  --tw-ring-shadow: var(--tw-ring-inset) 0 0 0 calc(2px + var(--tw-ring-offset-width)) var(--tw-ring-color);
  box-shadow: var(--tw-ring-offset-shadow), var(--tw-ring-shadow), var(--tw-shadow, 0 0 #0000);
}

.focus\:ring-primary:focus {
  --tw-ring-color: hsl(var(--primary));
}

/* Animations */
@keyframes accordion-down {
  from {
    height: 0;
  }
  to {
    height: var(--radix-accordion-content-height);
  }
}

@keyframes accordion-up {
  from {
    height: var(--radix-accordion-content-height);
  }
  to {
    height: 0;
  }
}

.animate-accordion-down {
  animation: accordion-down 0.2s ease-out;
}

.animate-accordion-up {
  animation: accordion-up 0.2s ease-out;
}

/* Gojiberry-style Blue/White Gradients and Effects */
.gojiberry-gradient {
  background: linear-gradient(135deg, 
    hsl(217.2, 91.2%, 97%) 0%, 
    hsl(217.2, 91.2%, 95%) 25%,
    hsl(221.2, 83.2%, 97%) 50%, 
    hsl(217.2, 91.2%, 96%) 75%, 
    hsl(217.2, 91.2%, 95%) 100%);
}

.gojiberry-hero-gradient {
  background: linear-gradient(135deg, 
    hsl(0, 0%, 100%) 0%,
    hsl(217.2, 91.2%, 95%) 25%,
    hsl(221.2, 83.2%, 88%) 50%, 
    hsl(217.2, 91.2%, 75%) 75%, 
    hsl(221.2, 83.2%, 65%) 100%);
}

.notification-badge {
  background: linear-gradient(135deg, 
    hsl(217.2, 91.2%, 59.8%) 0%, 
    hsl(221.2, 83.2%, 53.3%) 100%);
  box-shadow: 0 4px 14px hsl(217.2, 91.2%, 59.8% / 0.3);
  border: 1px solid hsl(217.2, 91.2%, 70%);
}

/* Glass Prism Effects */
.glass-prism {
  background: linear-gradient(145deg, 
    hsla(0, 0%, 100%, 0.25) 0%, 
    hsla(0, 0%, 100%, 0.1) 50%,
    hsla(0, 0%, 100%, 0.05) 100%);
  backdrop-filter: blur(20px);
  border: 1px solid hsla(0, 0%, 100%, 0.18);
  box-shadow: 
    0 8px 32px hsla(0, 0%, 0%, 0.1),
    inset 0 1px 0 hsla(0, 0%, 100%, 0.4);
}

.glass-prism-card {
  background: linear-gradient(145deg, 
    hsla(217.2, 91.2%, 98%, 0.8) 0%, 
    hsla(217.2, 91.2%, 96%, 0.6) 100%);
  backdrop-filter: blur(16px);
  border: 1px solid hsla(217.2, 91.2%, 80%, 0.3);
  box-shadow: 
    0 8px 32px hsla(217.2, 91.2%, 20%, 0.1),
    inset 0 1px 0 hsla(0, 0%, 100%, 0.6);
}

/* Enhanced Glass Prism Button */
.glass-prism-button {
  background: linear-gradient(145deg, 
    hsla(217.2, 91.2%, 75%, 0.9) 0%, 
    hsla(221.2, 83.2%, 65%, 0.8) 50%,
    hsla(217.2, 91.2%, 55%, 0.9) 100%) !important;
  backdrop-filter: blur(15px) !important;
  border: 2px solid hsla(0, 0%, 100%, 0.3) !important;
  box-shadow: 
    0 12px 24px hsla(217.2, 91.2%, 20%, 0.2),
    inset 0 1px 0 hsla(0, 0%, 100%, 0.5) !important;
  color: white !important;
  font-weight: 600 !important;
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1) !important;
  transform: perspective(1000px) rotateX(0deg) rotateY(0deg);
}

.glass-prism-button:hover {
  background: linear-gradient(145deg, 
    hsla(217.2, 91.2%, 65%, 0.95) 0%, 
    hsla(221.2, 83.2%, 55%, 0.9) 50%,
    hsla(217.2, 91.2%, 45%, 0.95) 100%) !important;
  transform: perspective(1000px) rotateX(-2deg) rotateY(2deg) translateY(-8px) scale(1.05) !important;
  box-shadow: 
    0 20px 40px hsla(217.2, 91.2%, 20%, 0.3),
    inset 0 2px 0 hsla(0, 0%, 100%, 0.6) !important;
  border-color: hsla(0, 0%, 100%, 0.5) !important;
  color: white !important;
}

.glass-prism-button:active {
  transform: perspective(1000px) rotateX(2deg) rotateY(-1deg) translateY(-4px) scale(0.98) !important;
  transition: all 0.1s ease !important;
}

/* Scroll Animations */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideInRight {
  from {
    opacity: 0;
    transform: translateX(30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.9);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
