            </div>
            <div className="text-3xl font-bold bg-gradient-to-r from-gray-900 to-gray-700 dark:from-white dark:to-gray-300 bg-clip-text text-transparent mb-2">
              {statsLoading ? "..." : `${dashboardStats?.conversionRate || 0}%`}
