      {/* Business Info & Policies Section - Only show if business info exists */}
      {(page.businessHours || page.businessAddress || page.contactPhone || page.contactEmail || page.cancellationPolicy) ? (
        <section className="py-16 bg-muted/30">
          <div className="container mx-auto px-6">
            <div className="text-center mb-12">
              <h2 className="text-3xl lg:text-4xl font-bold text-foreground mb-4">Business Information</h2>
              <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
                Everything you need to know before booking your appointment
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 max-w-6xl mx-auto">

              {/* Location - Only show if address exists */}
              {page.businessAddress && (
                <Card className="bg-card/60 backdrop-blur-sm border-border/20 hover:border-border/40 transition-all duration-300">
                  <CardContent className="p-6">
                    <div className="flex items-center space-x-3 mb-4">
                      <div 
                        className="w-10 h-10 rounded-lg flex items-center justify-center"
                        style={{ backgroundColor: `${themeStyles?.primaryColor || '#2563eb'}20` }}
                      >
                        <MapPin className="h-5 w-5" style={{ color: themeStyles?.primaryColor || '#2563eb' }} />
                      </div>
                      <h3 className="font-semibold text-foreground">Location</h3>
                    </div>
                    <div className="text-sm text-muted-foreground space-y-1" data-testid="business-location">
                      {page.businessAddress.split('\n').map((line: string, index: number) => (
                        <p key={index}>{line}</p>
                      ))}
                      <a 
                        href={`https://maps.google.com/?q=${encodeURIComponent(page.businessAddress)}`} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="inline-flex items-center text-xs mt-2 text-primary hover:underline"
                        data-testid="link-map"
                      >
                        <ExternalLink className="h-3 w-3 mr-1" />
                        View on Map
                      </a>
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Contact - Only show if contact info exists and showContactInfo is enabled */}
              {(page.contactPhone || page.contactEmail) && page.showContactInfo === 'true' && (
                <Card className="bg-card/60 backdrop-blur-sm border-border/20 hover:border-border/40 transition-all duration-300">
                  <CardContent className="p-6">
                    <div className="flex items-center space-x-3 mb-4">
                      <div 
                        className="w-10 h-10 rounded-lg flex items-center justify-center"
                        style={{ backgroundColor: `${themeStyles?.primaryColor || '#2563eb'}20` }}
                      >
                        <Phone className="h-5 w-5" style={{ color: themeStyles?.primaryColor || '#2563eb' }} />
                      </div>
                      <h3 className="font-semibold text-foreground">Contact</h3>
                    </div>
                    <div className="space-y-3 text-sm">
                      {page.contactPhone && (
                        <div className="flex items-center justify-between">
                          <span className="text-muted-foreground">Phone:</span>
                          <Button
                            variant="ghost"
                            size="sm"
                            className="h-auto p-1 text-foreground hover:bg-primary/10"
                            onClick={() => {
                              navigator.clipboard.writeText(page.contactPhone);
                              toast({ title: 'Phone number copied to clipboard!' });
                            }}
                            data-testid="button-copy-phone"
                          >
                            <span className="mr-2">{page.contactPhone}</span>
                            <Copy className="h-3 w-3" />
                          </Button>
                        </div>
                      )}
                      {page.contactEmail && (
                        <div className="flex items-center justify-between">
                          <span className="text-muted-foreground">Email:</span>
                          <Button
                            variant="ghost"
                            size="sm"
                            className="h-auto p-1 text-foreground hover:bg-primary/10"
                            onClick={() => {
                              navigator.clipboard.writeText(page.contactEmail);
                              toast({ title: 'Email copied to clipboard!' });
                            }}
                            data-testid="button-copy-email"
                          >
                            <span className="mr-2">{page.contactEmail}</span>
                            <Copy className="h-3 w-3" />
                          </Button>
                        </div>
                      )}
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Policies - Only show if cancellation policy exists */}
              {page.cancellationPolicy && (
                <Card className="bg-card/60 backdrop-blur-sm border-border/20 hover:border-border/40 transition-all duration-300">
                  <CardContent className="p-6">
                    <div className="flex items-center space-x-3 mb-4">
                      <div 
                        className="w-10 h-10 rounded-lg flex items-center justify-center"
                        style={{ backgroundColor: `${themeStyles?.primaryColor || '#2563eb'}20` }}
                      >
                        <FileText className="h-5 w-5" style={{ color: themeStyles?.primaryColor || '#2563eb' }} />
                      </div>
                      <h3 className="font-semibold text-foreground">Policies</h3>
                    </div>
                    <div className="text-sm text-muted-foreground" data-testid="business-policies">
                      <div className="flex items-start space-x-2">
                        <CheckCircle className="h-3 w-3 mt-0.5 flex-shrink-0" style={{ color: themeStyles?.primaryColor || '#2563eb' }} />
                        <span>{page.cancellationPolicy}</span>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              )}
            </div>
          </div>
        </section>
      ) : (
        /* Fallback Section - Show just business name when no business info */
        <section className="py-16 bg-muted/30">
          <div className="container mx-auto px-6">
            <div className="text-center">
              <h2 className="text-3xl lg:text-4xl font-bold text-foreground mb-4" data-testid="business-name-fallback">
                {page.title}
              </h2>
              <p className="text-lg text-muted-foreground">
                Ready to book your appointment
              </p>
            </div>
          </div>
        </section>
      )}

      {/* Booking Modal */}
      <BookingModal 
        open={showBookingModal} 
        onClose={() => setShowBookingModal(false)}
        page={page}
        services={services}
      />
    </div>
  );
}

client/src/pages/signup.tsx.content:
import { useState } from 'react';
import { useLocation } from 'wouter';
import { useAuth } from '@/hooks/use-auth';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Checkbox } from '@/components/ui/checkbox';
import { useToast } from '@/hooks/use-toast';
import { CalendarDays, Home, Eye, EyeOff } from 'lucide-react';
import EmailConfirmationModal from '@/components/modals/email-confirmation-modal';

export default function Signup() {
  const [, setLocation] = useLocation();
  const { signup, signInWithGoogle } = useAuth();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [showEmailConfirmation, setShowEmailConfirmation] = useState(false);
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    password: '',
    remember: false,
    agreeToTerms: false
  });
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.agreeToTerms) {
      toast({
        title: "Please accept the terms",
        description: "You must agree to the Terms of Service and Privacy Policy.",
        variant: "destructive",
      });
      return;
    }

    setLoading(true);

    try {
      const result = await signup(formData.email, formData.password, formData.fullName);

      if (result.needsEmailConfirmation) {
        setShowEmailConfirmation(true);
        toast({
          title: "Check your email!",
          description: "We sent you a confirmation link to complete your signup.",
        });
      } else {
        toast({
          title: "Account created!",
          description: "Welcome to BookingGen. Let's get you started.",
        });
        setLocation('/dashboard');
      }
    } catch (error) {
      toast({
        title: "Signup failed",
        description: "Failed to create account. Please try again.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSignUp = async () => {
    try {
      await signInWithGoogle();
      // Note: Supabase OAuth will handle the redirect, so no need to manually redirect
    } catch (error) {
      toast({
        title: "Google Sign Up failed",
        description: "Failed to sign up with Google. Please try again.",
        variant: "destructive",
      });
    }
  };

  return (
    <div className="min-h-screen page-gradient relative overflow-hidden">
      {/* Glass Prism Background Elements */}
      <div className="absolute inset-0 bg-gradient-to-br from-blue-50/80 via-white to-blue-50/80 bg-overlay"></div>
      <div className="absolute top-10 left-10 w-72 h-72 glass-prism rounded-full opacity-30 animate-float bg-overlay"></div>
      <div className="absolute top-32 right-20 w-96 h-96 glass-prism rounded-full opacity-20 animate-float bg-overlay" style={{animationDelay: '1.5s'}}></div>
      <div className="absolute bottom-20 left-1/3 w-48 h-48 glass-prism rounded-full opacity-25 animate-float bg-overlay" style={{animationDelay: '3s'}}></div>

      <div className="relative flex items-center justify-center min-h-screen p-6 content-layer">
        <div className="w-full max-w-md glass-prism-card rounded-3xl p-8 hover-lift animate-fade-in-up">
          <div className="flex justify-start mb-4">
            <Button 
              variant="ghost" 
              size="sm"
              onClick={() => setLocation('/')}
              className="flex items-center space-x-2 text-muted-foreground hover:text-foreground bg-white/10 backdrop-blur-sm border border-white/20 hover:bg-white/20 transition-all duration-300 rounded-lg"
              data-testid="button-back-home"
            >
              <Home className="h-4 w-4" />
              <span>Back to Homepage</span>
            </Button>
          </div>

          <div className="text-center mb-8">
            <div className="flex items-center justify-center space-x-3 mb-4">
              <div className="w-10 h-10 glass-prism rounded-lg flex items-center justify-center">
                <CalendarDays className="h-6 w-6 text-primary" />
              </div>
              <span className="text-xl font-bold text-foreground">BookingGen</span>
            </div>
            <h1 className="text-2xl font-bold text-foreground mb-2">Create your account</h1>
            <p className="text-muted-foreground">Start creating beautiful booking pages today</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <Label htmlFor="fullName" className="text-foreground font-medium">Full Name</Label>
              <Input
                id="fullName"
                type="text"
                placeholder="Enter your full name"
                value={formData.fullName}
                onChange={(e) => setFormData(prev => ({ ...prev, fullName: e.target.value }))}
                required
                data-testid="input-fullname"
                className="glass-input mt-2"
              />
            </div>

            <div>
              <Label htmlFor="email" className="text-foreground font-medium">Email</Label>
              <Input
                id="email"
                type="email"
                placeholder="Enter your email"
                value={formData.email}
                onChange={(e) => setFormData(prev => ({ ...prev, email: e.target.value }))}
                required
                data-testid="input-email"
                className="glass-input mt-2"
              />
            </div>

            <div>
              <Label htmlFor="password" className="text-foreground font-medium">Password</Label>
              <div className="relative mt-2">
                <Input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  placeholder="Create a password"
                  value={formData.password}
                  onChange={(e) => setFormData(prev => ({ ...prev, password: e.target.value }))}
                  required
                  data-testid="input-password"
                  className="glass-input pr-10"
                />
                <Button
                  type="button"
                  variant="ghost"
                  size="sm"
                  className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                  onClick={() => setShowPassword(!showPassword)}
                  data-testid="button-toggle-password"
                >
                  {showPassword ? (
                    <EyeOff className="h-4 w-4 text-muted-foreground" />
                  ) : (
                    <Eye className="h-4 w-4 text-muted-foreground" />
                  )}
                </Button>
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center space-x-2">
                <Checkbox 
                  id="remember"
                  checked={formData.remember}
                  onCheckedChange={(checked) => setFormData(prev => ({ ...prev, remember: !!checked }))}
                  data-testid="checkbox-remember"
                />
                <Label htmlFor="remember" className="text-sm text-foreground">Remember me</Label>
              </div>

              <div className="flex items-start space-x-2">
                <Checkbox 
                  id="terms"
                  checked={formData.agreeToTerms}
                  onCheckedChange={(checked) => setFormData(prev => ({ ...prev, agreeToTerms: !!checked }))}
                  data-testid="checkbox-terms"
                />
                <Label htmlFor="terms" className="text-sm leading-5 text-foreground">
                  I agree to the{' '}
                  <Button variant="link" className="p-0 h-auto text-primary text-sm hover:text-primary/80 font-medium">
                    Terms of Service
                  </Button>
                  {' '}and{' '}
                  <Button variant="link" className="p-0 h-auto text-primary text-sm hover:text-primary/80 font-medium">
                    Privacy Policy
                  </Button>
                </Label>
              </div>
            </div>

            <Button 
              type="submit" 
              size="lg"
              className="w-full h-12 glass-prism-button px-6 py-2 rounded-full font-semibold text-[15px] shadow-md"
              disabled={loading}
              data-testid="button-create-account"
            >
              {loading ? "Creating Account..." : "Create Account"}
            </Button>

            <div className="relative">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-white/20"></div>
              </div>
              <div className="relative flex justify-center text-sm">
                <span className="px-4 bg-white/5 backdrop-blur-sm text-muted-foreground rounded-full">Or continue with</span>
              </div>
            </div>

            <Button 
              type="button" 
              variant="outline" 
              size="lg"
              className="w-full h-12 bg-white/10 backdrop-blur-sm border border-white/20 hover:bg-white/20 transition-all duration-300 rounded-full"
              onClick={handleGoogleSignUp}
              data-testid="button-google-signup"
            >
              <svg className="mr-2 h-4 w-4" viewBox="0 0 24 24">
                <path fill="currentColor" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                <path fill="currentColor" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                <path fill="currentColor" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                <path fill="currentColor" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
              </svg>
              Sign up with Google
            </Button>
          </form>

          <div className="text-center mt-6">
            <p className="text-muted-foreground">
              Already have an account?{' '}
              <Button 
                variant="link" 
                className="p-0 text-primary hover:text-primary/80 font-medium"
                onClick={() => setLocation('/login')}
                data-testid="link-signin"
              >
                Sign in
              </Button>
            </p>
          </div>
        </div>
      </div>

      {/* Email Confirmation Modal */}
      <EmailConfirmationModal
        isOpen={showEmailConfirmation}
        onClose={() => setShowEmailConfirmation(false)}
        email={formData.email}
      />
    </div>
  );
}

client/src/components/auth/auth-guard.ts.content:
import { useAuth } from '@/hooks/use-auth';
import { useLocation } from 'wouter';
import { useEffect } from 'react';

interface AuthGuardProps {
  children: React.ReactNode;
}

export default function AuthGuard({ children }: AuthGuardProps) {
  const { user, loading } = useAuth();
  const [, setLocation] = useLocation();

  useEffect(() => {
    if (!loading && !user) {
      setLocation('/login');
    }
  }, [user, loading, setLocation]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!user) {
    return null;
  }

  return <>{children}</>;
}

client/src/components/dashboard/appointm.content:
import { useQuery, useMutation } from '@tanstack/react-query';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Check, X, Calendar, Mail, Filter, Download } from 'lucide-react';
import { apiRequest, queryClient } from '@/lib/queryClient';
import { useToast } from '@/hooks/use-toast';

export default function AppointmentsList() {
  const { toast } = useToast();
  const { data: appointments = [], isLoading } = useQuery<any[]>({
    queryKey: ['/api/appointments'],
  });

  const updateAppointmentMutation = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: string }) => {
      const response = await apiRequest('PATCH', `/api/appointments/${id}`, { status });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/appointments'] });
      toast({
        title: "Success",
        description: "Appointment status updated successfully",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to update appointment status",
        variant: "destructive",
      });
    },
  });

  const handleStatusUpdate = (id: string, status: string) => {
    updateAppointmentMutation.mutate({ id, status });
  };

  const handleEmail = (email: string) => {
    window.open(`mailto:${email}`, '_blank');
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="animate-fade-in-up">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-bold bg-gradient-to-r from-gray-900 to-gray-700 dark:from-white dark:to-gray-300 bg-clip-text text-transparent">Appointments</h2>
          <p className="text-gray-600 dark:text-gray-300">Manage your upcoming and past appointments</p>
        </div>
        <div className="flex space-x-3">
          <Button variant="outline" className="glass-prism backdrop-blur-md bg-white/10 dark:bg-black/10 border border-white/20 hover:bg-white/20 dark:hover:bg-black/20 transition-all duration-300" data-testid="button-filter">
            <Filter className="h-4 w-4 mr-2" />
            Filter
          </Button>
          <Button variant="outline" className="glass-prism backdrop-blur-md bg-white/10 dark:bg-black/10 border border-white/20 hover:bg-white/20 dark:hover:bg-black/20 transition-all duration-300" data-testid="button-export">
            <Download className="h-4 w-4 mr-2" />
            Export
          </Button>
        </div>
      </div>

      {appointments.length === 0 ? (
        <Card className="glass-prism-card backdrop-blur-xl bg-white/10 dark:bg-black/10 border border-white/20 shadow-2xl">
          <CardContent className="p-12 text-center">
            <div className="text-6xl text-gray-400 mb-4">📅</div>
            <h3 className="text-xl font-semibold text-gray-800 dark:text-gray-100 mb-2">No appointments yet</h3>
            <p className="text-gray-600 dark:text-gray-400 mb-6">
              Once people start booking appointments through your pages, they'll appear here.
            </p>
            <Button 
              variant="default"
              className="glass-prism-button text-white shadow-lg backdrop-blur-lg" 
              data-testid="button-create-page-from-appointments"
            >
              Create Your First Booking Page
            </Button>
          </CardContent>
        </Card>
      ) : (
        <Card className="glass-prism-card backdrop-blur-xl bg-white/10 dark:bg-black/10 border border-white/20 shadow-2xl">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="glass-prism backdrop-blur-md bg-white/5 dark:bg-black/5 border-b border-white/10">
                <tr>
                  <th className="text-left py-4 px-6 text-sm font-medium text-gray-600 dark:text-gray-300">Customer</th>
                  <th className="text-left py-4 px-6 text-sm font-medium text-gray-600 dark:text-gray-300">Service</th>
                  <th className="text-left py-4 px-6 text-sm font-medium text-gray-600 dark:text-gray-300">Date & Time</th>
                  <th className="text-left py-4 px-6 text-sm font-medium text-gray-600 dark:text-gray-300">Status</th>
                  <th className="text-left py-4 px-6 text-sm font-medium text-gray-600 dark:text-gray-300">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {appointments.map((appointment: any) => (
                  <tr key={appointment.id}>
                    <td className="py-4 px-6">
                      <div className="flex items-center space-x-3">
                        <div className="w-10 h-10 bg-primary/10 rounded-full flex items-center justify-center">
                          <span className="text-sm font-medium text-primary">
                            {appointment.customerName?.charAt(0)}
                          </span>
                        </div>
                        <div>
                          <p className="font-medium text-foreground" data-testid={`customer-name-${appointment.id}`}>
                            {appointment.customerName}
                          </p>
                          <p className="text-sm text-muted-foreground" data-testid={`customer-email-${appointment.id}`}>
                            {appointment.customerEmail}
                          </p>
                        </div>
                      </div>
                    </td>
                    <td className="py-4 px-6">
                      <span className="text-foreground" data-testid={`service-name-${appointment.id}`}>
                        {appointment.serviceName || 'Service'}
                      </span>
                    </td>
                    <td className="py-4 px-6">
                      <div>
                        <p className="text-foreground">{appointment.date}</p>
                        <p className="text-sm text-muted-foreground">{appointment.time}</p>
                      </div>
                    </td>
                    <td className="py-4 px-6">
                      <Badge 
                        variant={appointment.status === 'pending' ? 'secondary' : 'default'}
                        className={
                          appointment.status === 'pending' ? 'bg-orange-100 text-orange-800' :
                          appointment.status === 'accepted' ? 'bg-green-100 text-green-800' :
                          appointment.status === 'declined' ? 'bg-red-100 text-red-800' :
                          'bg-blue-100 text-blue-800'
                        }
                        data-testid={`status-${appointment.id}`}
                      >
                        {appointment.status?.charAt(0).toUpperCase() + appointment.status?.slice(1)}
                      </Badge>
                    </td>
                    <td className="py-4 px-6">
                      <div className="flex space-x-2">
                        {appointment.status === 'pending' && (
                          <>
                            <Button 
                              size="sm" 
                              variant="ghost" 
                              className="text-green-600 hover:text-green-700 p-1"
                              data-testid={`button-accept-${appointment.id}`}
                              onClick={() => handleStatusUpdate(appointment.id, 'accepted')}
                              disabled={updateAppointmentMutation.isPending}
                            >
                              <Check className="h-4 w-4" />
                            </Button>
                            <Button 
                              size="sm" 
                              variant="ghost" 
                              className="text-red-600 hover:text-red-700 p-1"
                              data-testid={`button-decline-${appointment.id}`}
                              onClick={() => handleStatusUpdate(appointment.id, 'declined')}
                              disabled={updateAppointmentMutation.isPending}
                            >
                              <X className="h-4 w-4" />
                            </Button>
                          </>
                        )}
                        <Button 
                          size="sm" 
                          variant="ghost" 
                          className="text-blue-600 hover:text-blue-700 p-1"
                          data-testid={`button-reschedule-${appointment.id}`}
                        >
                          <Calendar className="h-4 w-4" />
                        </Button>
                        {appointment.customerEmail && (
                          <Button 
                            size="sm" 
                            variant="ghost" 
                            className="text-gray-600 hover:text-gray-700 p-1"
                            data-testid={`button-email-${appointment.id}`}
                            onClick={() => handleEmail(appointment.customerEmail)}
                          >
                            <Mail className="h-4 w-4" />
                          </Button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Card>
      )}
    </div>
  );
}

