          </div>
          <span className="text-xl font-bold bg-gradient-to-r from-gray-900 to-gray-700 dark:from-white dark:to-gray-300 bg-clip-text text-transparent">BookingGen</span>
        </div>
      </div>

      {/* Navigation */}
